import styles from './indicator.module.css'

export type IndicatorPlacement = 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end'

export interface IndicatorProps {
  children: React.ReactNode
  overlay: React.ReactNode
  placement?: IndicatorPlacement
  className?: string
}

export function Indicator({ children, overlay, placement = 'top-end', className }: IndicatorProps) {
  return (
    <div
      className={[styles.indicator, className].filter(Boolean).join(' ')}
      data-placement={placement}
    >
      {children}
      <div className={styles.overlay} aria-hidden>
        {overlay}
      </div>
    </div>
  )
}

@layer cascivo.component {
  .indicator {
    position: relative;
    display: inline-flex;
  }

  .overlay {
    position: absolute;
    z-index: 1;
    pointer-events: none;
  }

  .indicator[data-placement='top-start'] .overlay {
    inset-block-start: 0;
    inset-inline-start: 0;
    transform: translate(-25%, -25%);
  }
  .indicator[data-placement='top-end'] .overlay {
    inset-block-start: 0;
    inset-inline-end: 0;
    transform: translate(25%, -25%);
  }
  .indicator[data-placement='bottom-start'] .overlay {
    inset-block-end: 0;
    inset-inline-start: 0;
    transform: translate(-25%, 25%);
  }
  .indicator[data-placement='bottom-end'] .overlay {
    inset-block-end: 0;
    inset-inline-end: 0;
    transform: translate(25%, 25%);
  }
}
